import os
import json
import time
from typing import Any, Dict, Optional

class APICache:
    def __init__(self, cache_file: str, expiration_time: int = 3600):
        self.cache_file = cache_file
        self.expiration_time = expiration_time
        self.cache_data: Dict[str, Any] = {}
        self.load_cache()

    def load_cache(self):
        if os.path.exists(self.cache_file):
            with open(self.cache_file, 'r') as f:
                self.cache_data = json.load(f)

    def save_cache(self):
        with open(self.cache_file, 'w') as f:
            json.dump(self.cache_data, f)

    def get(self, key: str) -> Optional[Dict[str, Any]]:
        if key in self.cache_data:
            timestamp, data = self.cache_data[key]
            if time.time() - timestamp < self.expiration_time:
                return data
            else:
                del self.cache_data[key]  # Remove expired cache
        return None

    def set(self, key: str, data: Dict[str, Any]):
        self.cache_data[key] = (time.time(), data)
        self.save_cache()

    def clear_cache(self):
        self.cache_data.clear()
        if os.path.exists(self.cache_file):
            os.remove(self.cache_file)

